const goalsRaw = $('Get Active Goals').first().json;
const goalsArr = Array.isArray(goalsRaw) ? goalsRaw : [goalsRaw];
const events = $('Get Tomorrow Events').all().map(i => i.json);

const goalList = goalsArr.map(g => `- [${g.level}] ${g.title} (${g.category || ''})`).join('\n');
const eventList = events.length
  ? events.map(e => `- ${e.summary}: ${e.start?.dateTime || e.start?.date}`).join('\n')
  : '(빈 일정)';

const prompt = `사용자의 내일 일정과 이번 달 목표를 분석하여, 빈 시간에 넣을 수 있는 활동을 최대 3개 제안해주세요.

내일 기존 일정:
${eventList}

현재 목표:
${goalList}

규칙:
- 30분~2시간 단위
- 현실적인 계획
- 각 제안에 연관 목표 명시

반드시 아래 JSON 배열만 출력 (다른 텍스트 금지):
[{"title":"","start_time":"HH:MM","end_time":"HH:MM","goal":"","reason":""}]`;

return [{ json: { prompt } }];

const raw = $('Generate Suggestions').first().json?.message?.content
  || $('Generate Suggestions').first().json?.choices?.[0]?.message?.content || '[]';
let suggestions = [];
try {
  const match = raw.match(/\[.*\]/s);
  suggestions = match ? JSON.parse(match[0]) : [];
} catch(e) { suggestions = []; }

if (!suggestions.length) {
  return [{ json: { noSuggestions: true } }];
}

const today = new Date();
const tomorrow = new Date(today);
tomorrow.setDate(today.getDate() + 1);
const dateStr = tomorrow.toISOString().split('T')[0];

const msg = '📅 내일 일정 최적화 제안이에요!\n\n'
  + suggestions.map((s, i) =>
    `⏰ ${s.start_time}~${s.end_time} | ${s.title}\n   → ${s.goal}: ${s.reason}`
  ).join('\n\n')
  + '\n\n✅ 위 일정들이 Google Calendar에 자동 추가됩니다.';

return suggestions.map(s => ({
  json: {
    summary: s.title,
    startDateTime: `${dateStr}T${s.start_time}:00`,
    endDateTime:   `${dateStr}T${s.end_time}:00`,
    description:   `목표: ${s.goal} | ${s.reason}`,
    msg
  }
}));
